using BgControls.Windows.Controls;using BgControls.Windows.DragDrop;namespace BgControls.Windows.Controls.DragDrop;internal class DragDropProvider : DragDropProviderBase{    private bool isDropPossible;    private Dictionary<int, bool> approvedDestinations = new Dictionary<int, bool>();    private WeakReference rootVisualReference;    private bool IsCancellingDrag { get; set; }    public UIElement? RootVisual    {        get        {            if (rootVisualReference != null && rootVisualReference.IsAlive)            {                return rootVisualReference.Target as UIElement;            }            return null;        }        set        {            rootVisualReference = new WeakReference(value);        }    }    private Point RelativeStartPoint { get; set; }    public override void CancelDrag()    {        CancelDragging();        Reset();    }    public override void StartDrag(FrameworkElement dragSource, object payload, object dragCue)    {        base.Options.Payload = payload;        base.Options.DragCue = dragCue;        DragDropManager.DoDragDrop(dragSource, payload, DragDropEffects.All, DragDropKeyStates.None, dragCue, default(Point), default(Point));    }    public override void SetAllowDrag(DependencyObject obj, bool value)    {        DragDropManager.SetAllowDrag(obj, value);        if (value)        {            DragDropManager.AddDragInitializeHandler(obj, OnDragInitialized);        }        else        {            DragDropManager.RemoveDragInitializeHandler(obj, OnDragInitialized);        }    }    public void OnDragInitialized(object sender, DragInitializeEventArgs e)    {        base.IsDragging = true;        base.Options.Status = DragStatus.DragQuery;        base.Options.Source = (e.OriginalSource as FrameworkElement) ?? (e.Source as FrameworkElement);        FrameworkElement frameworkElement = ApplicationHelper.GetFirstLogicalRoot(base.Options.Source);        if (frameworkElement is Popup)        {            frameworkElement = ((Popup)frameworkElement).Child as FrameworkElement;        }        GeneralTransform generalTransform = base.Options.Source.TransformToVisual(frameworkElement);        Point point = generalTransform.Transform(e.RelativeStartPoint);        RootVisual = frameworkElement;        base.Options.MouseClickPoint = point;        RelativeStartPoint = e.RelativeStartPoint;        base.Options.CurrentDragPoint = point;        var e2 = RaiseDragQuery();        bool? queryResult = e2.QueryResult;        if (queryResult ?? false)        {            base.Options.Status = DragStatus.DragInProgress;            RaiseDragInfo();            _ = base.DragCueOffset;            if (base.DragCueOffset.X != 0.0 || base.DragCueOffset.Y != 0.0)            {                e.DragVisualOffset = base.DragCueOffset;            }            e.DragVisual = base.Options.DragCue;            e.Data = base.Options.Payload;            e.AllowedEffects = DragDropEffects.All;            DragDropManager.AddDragDropCompletedHandler(base.Options.Source, OnDragDropCompleted);            DragDropManager.AddGiveFeedbackHandler(base.Options.Source, OnGiveFeedBack);            DragDropManager.AddQueryContinueDragHandler(base.Options.Source, OnQueryContinue);            DragDropManager.AddDragCuePositionEventHandler(base.Options.Source, OnPositioningDragCue);            e.Handled = e2.Handled;        }        e.Cancel = !(queryResult ?? false);        if (e.Cancel)        {            Reset();        }    }    public void OnGiveFeedBack(object sender, Windows.DragDrop.GiveFeedbackEventArgs args)    {        if (base.Options.CurrentCursor != null)        {            args.SetCursor(base.Options.CurrentCursor);        }        else        {            args.SetCursor(Cursors.Arrow);        }        args.Handled = true;    }    public override void SetAllowDrop(DependencyObject obj, bool value)    {        FrameworkElement frameworkElement = obj as FrameworkElement;        if (frameworkElement != null && value)        {            frameworkElement.AllowDrop = value;            DragDropManager.RemoveDragOverHandler(frameworkElement, OnElementDragOver);            DragDropManager.RemoveDragLeaveHandler(frameworkElement, OnElementDragLeave);            DragDropManager.RemoveDragDropCompletedHandler(frameworkElement, OnElementDragDropCompleted);            DragDropManager.RemoveDropHandler(frameworkElement, OnElementDrop);            DragDropManager.AddDragOverHandler(frameworkElement, OnElementDragOver);            DragDropManager.AddDragLeaveHandler(frameworkElement, OnElementDragLeave);            DragDropManager.AddDragDropCompletedHandler(frameworkElement, OnElementDragDropCompleted);            DragDropManager.AddDropHandler(frameworkElement, OnElementDrop);        }        else if (frameworkElement != null)        {            frameworkElement.AllowDrop = value;            DragDropManager.RemoveDragOverHandler(frameworkElement, OnElementDragOver);            DragDropManager.RemoveDragLeaveHandler(frameworkElement, OnElementDragLeave);            DragDropManager.RemoveDragDropCompletedHandler(frameworkElement, OnElementDragDropCompleted);            DragDropManager.RemoveDropHandler(frameworkElement, OnElementDrop);        }    }    protected override void AdjustScrollViewer(IScrollViewerAdapter viewer, Point currentPoint)    {        throw new NotImplementedException();    }    internal override void SetCursor()    {    }    internal override void ResetCursor()    {    }    public override void Dispose()    {    }    private void OnQueryContinue(object sender, Windows.DragDrop.QueryContinueDragEventArgs args)    {        if (IsCancellingDrag)        {            args.Action = DragAction.Cancel;        }    }    public void OnElementDragOver(object sender, Windows.DragDrop.DragEventArgs e)    {        if (base.Options.Effects.HasValue)        {            e.Effects = base.Options.Effects.Value;        }        DragStatus status = base.Options.Status;        base.Options.Destination = sender as FrameworkElement;        base.Options.Status = DragStatus.DropDestinationQuery;        if (base.Options.Destination != null)        {            base.Options.RelativeDragPoint = e.GetPosition(base.Options.Destination);            base.Options.CurrentDragPoint = e.GetPosition(RootVisual ?? ApplicationHelper.GetRootVisual(base.Options.Destination));        }        base.Options.DropDataObject = e.Data as DataObject;        DragDropQueryEventArgs e2 = RaiseDropQuery();        bool? queryResult = e2.QueryResult;        bool? flag = null;        if (queryResult == true)        {            base.Options.Status = DragStatus.DropSourceQuery;            flag = RaiseDragQuery().QueryResult;        }        bool? flag2 = queryResult;        if (flag2 == true && flag2.HasValue && (flag == true || base.Options.Source == null))        {            base.Options.Status = DragStatus.DropPossible;            RaiseDropInfo();            RaiseDragInfo();            OnDropPossible();            isDropPossible = true;            if (approvedDestinations.ContainsKey(base.Options.Destination.GetHashCode()))            {                approvedDestinations[base.Options.Destination.GetHashCode()] = true;            }            else            {                approvedDestinations.Add(base.Options.Destination.GetHashCode(), value: true);            }        }        else        {            base.Options.Status = DragStatus.DropImpossible;            isDropPossible = false;            if (approvedDestinations.ContainsKey(base.Options.Destination.GetHashCode()))            {                approvedDestinations[base.Options.Destination.GetHashCode()] = false;            }            else            {                approvedDestinations.Add(base.Options.Destination.GetHashCode(), value: false);            }            if (status != DragStatus.DropImpossible)            {                NotifyPreviousApprovedDestination();            }        }        bool? flag3 = queryResult;        e.Effects = ((flag3 == true && flag3.HasValue && (flag == true || base.Options.Source == null)) ? e.AllowedEffects : DragDropEffects.None);        e.Handled = e2.Handled;    }    public void OnElementDragLeave(object sender, Windows.DragDrop.DragEventArgs args)    {        OnDropImpossible();        isDropPossible = false;        if (base.Options.Destination != null)        {            if (approvedDestinations.ContainsKey(base.Options.Destination.GetHashCode()))            {                approvedDestinations[base.Options.Destination.GetHashCode()] = false;            }            else            {                approvedDestinations.Add(base.Options.Destination.GetHashCode(), value: false);            }        }    }    public void OnElementDrop(object sender, Windows.DragDrop.DragEventArgs e)    {        base.Options.Destination = sender as FrameworkElement;        base.Options.DropDataObject = e.Data as DataObject;        FinishDrag();        e.Handled = true;    }    public void OnElementDragDropCompleted(object sender, DragDropCompletedEventArgs e)    {    }    private void FinishDrag()    {        if (base.Options.Destination != null && (approvedDestinations.ContainsKey(base.Options.Destination.GetHashCode()) ? approvedDestinations[base.Options.Destination.GetHashCode()] : isDropPossible))        {            base.Options.Status = DragStatus.DragComplete;            RaiseDragInfo();            base.Options.Status = DragStatus.DropComplete;            RaiseDropInfo();        }        else if (base.IsDragging)        {            CancelDragging();        }        Reset();    }    private void CancelDragging()    {        if (base.IsDragging)        {            base.IsDragging = false;            NotifyPreviousApprovedDestination();            base.Options.Status = DragStatus.DragCancel;            RaiseDragInfo();            base.Options.Status = DragStatus.None;            IsCancellingDrag = true;        }    }    internal override void Reset()    {        base.Reset();        if (base.ScrollViewerScrollTimer != null)        {            base.ScrollViewerScrollTimer.Stop();        }        RelativeStartPoint = default(Point);        approvedDestinations.Clear();    }    public void OnDragDropCompleted(object subject, DragDropCompletedEventArgs args)    {        if (base.IsDragging)        {            FinishDrag();        }    }    public void OnPositioningDragCue(object sender, DragCuePositionEventArgs args)    {        if (base.Options.DragCue is FrameworkElement { ActualWidth: > 0.0, ActualHeight: > 0.0 } frameworkElement)        {            Point dragCueOffset = default(Point);            if (frameworkElement.ActualWidth < RelativeStartPoint.X)            {                dragCueOffset.X = RelativeStartPoint.X - frameworkElement.ActualWidth / 2.0;            }            if (frameworkElement.ActualHeight < RelativeStartPoint.Y)            {                dragCueOffset.Y = RelativeStartPoint.Y - frameworkElement.ActualHeight / 2.0;            }            args.DragCueOffset = dragCueOffset;        }    }}